@import url('https://fonts.googleapis.com/icon?family=Material+Symbols+Outlined');

:host {
  font-family: var(--inter-font);
  display: flex;
  justify-content: center;
}

[ngTabs] {
  overflow: hidden;
  width: 600px;
  height: 200px;
  border-radius: 0.5rem;
  border: 1px solid color-mix(in srgb, var(--primary-contrast) 10%, transparent);
  display: flex;
}

[ngTabList] {
  padding: 0;
  display: flex;
  flex-direction: column;
  list-style: none;
  position: relative;
  border-right: 1px solid color-mix(in srgb, var(--primary-contrast) 10%, transparent);
}

[ngTab] {
  flex: 1;
  outline: none;
  width: 80px;
  cursor: pointer;
  color: color-mix(in srgb, var(--primary-contrast) 60%, transparent);
  display: grid;
  place-items: center;
}

[ngTab][aria-selected='false']:focus {
  outline-offset: -8px;
  border-radius: 0.7rem;
  outline: 2px solid var(--bright-blue);
}

[ngTab]:hover {
  background-color: color-mix(in srgb, var(--bright-blue) 5%, transparent);
}

[ngTab][aria-selected='true'] {
  color: var(--page-background);
  background-color: var(--bright-blue);
  border-top-left-radius: 0.5rem;
  border-bottom-left-radius: 0.5rem;
}

.sliding-window {
  height: 300%;
  display: flex;
  flex-direction: column;
  transition: all 0.2s ease-in-out;
  flex: 1;
}

[ngTabList]:has([ngTab]:nth-child(1)[aria-selected='true']) ~ .sliding-window {
  transform: translateY(0%);
}
[ngTabList]:has([ngTab]:nth-child(2)[aria-selected='true']) ~ .sliding-window {
  transform: translateY(-33.333%);
}
[ngTabList]:has([ngTab]:nth-child(3)[aria-selected='true']) ~ .sliding-window {
  transform: translateY(-66.666%);
}

[ngTabPanel] {
  display: grid;
  place-items: center;
  padding: 1rem;
  flex: 1;
}

[ngTabPanel]:focus {
  outline-offset: -4px;
  border-radius: 0.5rem;
  outline: 2px solid var(--bright-blue);
}

@use '@angular/docs/styles/media-queries' as mq;

.two-column-step {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 3rem;
  text-align: left;
  width: 100%;
  max-width: 1200px;
  margin: 0 auto;
  box-sizing: border-box;
  background-color: var(--card-background);
  border: 1px solid var(--senary-contrast);
  border-radius: 0.5rem;
  padding: 2rem;

  @include mq.for-tablet-down {
    grid-template-columns: 1fr;
    gap: 2rem;
    padding: 1.5rem;
  }

  @include mq.for-phone-only {
    padding: 1rem;
  }
}

.step-description {
  display: flex;
  flex-direction: column;
  gap: 1.5rem;

  .header {
    font-size: 1.5rem;
    font-weight: 500;
  }

  .description {
    font-size: 1.1rem;
    line-height: 1.6;
    color: var(--secondary-contrast);
  }
}

.step-code {
  display: flex;
  flex-direction: column;
  gap: 1.5rem;
  min-width: 0;

  .code-block {
    background: var(--card-background);
    border: 1px solid var(--senary-contrast);
    border-radius: 0.5rem;
    font-size: 0.9rem;
    overflow: auto;

    .code-header {
      display: flex;
      padding: 0.75rem;
      background: var(--subtle-purple);
      border-radius: 0.25rem 0.25rem 0 0;
      transition: background 0.3s ease;

      & > span {
        background-image: var(--purple-to-blue-horizontal-gradient);
        background-clip: text;
        color: transparent;
        font-size: 0.875rem;
        font-style: normal;
        font-weight: 400;
        line-height: 1.4rem;
        letter-spacing: -0.00875rem;
        margin: 0;
        word-wrap: break-word;
        width: fit-content;
      }
    }

    pre {
      font-family: 'JetBrains Mono', monospace;
      margin: 0;
      color: #a9b7c6;
    }
  }
}

@use '@angular/docs/styles/media-queries' as mq;

