  overflow-y: auto;
  overflow-x: hidden;
  height: 100vh;
  padding: 0;
  margin: 0;
  padding-block: 1.5rem;
  font-size: 0.875rem;
  box-sizing: border-box;

  height: max-content;
  max-height: calc(var(--fixed-content-height) - var(--layout-padding) - 67px);
  padding-block-start: 1rem;
  padding-block-end: 0;
