import { combineLatest, from, isObservable, Observable } from 'rxjs';
import { distinctUntilChanged } from 'rxjs/operators';

type Primitive = string | number | bigint | boolean | symbol | null | undefined;

type ObservableOrPromise<T> = Observable<T> | PromiseLike<T>;

type ObservableDictionary<PO> = Required<{
  [Key in keyof PO]: Observable<unknown>;
}>;

export type PotentialObservableResult<PO, ExtendedResult = never> =
  PO extends ObservableOrPromise<infer Result>
    ? Result | ExtendedResult
    : PO extends Primitive
      ? PO
      : keyof PO extends never
        ? PO
        : PO extends ObservableDictionary<PO>
          ?
              | {
                  [Key in keyof PO]: PO[Key] extends Observable<infer Value>
                    ? Value
                    : never;
                }
              | ExtendedResult
          : PO;

export function fromPotentialObservable<PO>(
  potentialObservable: PO
): Observable<PotentialObservableResult<PO>> {
  type Result = ReturnType<typeof fromPotentialObservable<PO>>;

  if (isObservable(potentialObservable)) {
    return potentialObservable as Result;
  }

  if (isObservableDictionary(potentialObservable)) {
    return combineLatest(
      toDistinctObsDictionary(potentialObservable)
    ) as Result;
  }

  if (isPromiseLike(potentialObservable)) {
    return from(potentialObservable) as Result;
  }

  return new Observable<PO>((subscriber) => {
    subscriber.next(potentialObservable);
  }) as Result;
}

function isPromiseLike(value: unknown): value is PromiseLike<unknown> {
  return typeof (value as PromiseLike<unknown>)?.then === 'function';
}

function isObservableDictionary(
  value: unknown
): value is Record<string, Observable<unknown>> {
  return (
    isDictionary(value) &&
    Object.keys(value).length > 0 &&
    Object.values(value).every(isObservable)
  );
}

function isDictionary(value: unknown): value is Record<string, unknown> {
  return !!value && typeof value === 'object' && !Array.isArray(value);
}

function toDistinctObsDictionary<
  OD extends Record<string, Observable<unknown>>,
>(obsDictionary: OD): OD {
  return Object.keys(obsDictionary).reduce(
    (acc, key) => ({
      ...acc,
      [key]: obsDictionary[key].pipe(distinctUntilChanged()),
    }),
    {} as OD
  );
}

import * as path from 'path';
import { createRule } from '../../rule-creator';
import {
  getNgRxStores,
  isPropertyDefinition,
  isTSTypeReference,
  isCallExpression,
  isTSInstantiationExpression,
} from '../../utils';
import type { TSESTree } from '@typescript-eslint/utils';

export const noTypedStore = 'noTypedStore';
export const noTypedStoreSuggest = 'noTypedStoreSuggest';

type MessageIds = typeof noTypedStore | typeof noTypedStoreSuggest;
type Options = readonly [];

export default createRule<Options, MessageIds>({
  name: path.parse(__filename).name,
  meta: {
    type: 'suggestion',
    hasSuggestions: true,
    docs: {
      description: 'The global store should not be typed.',
      ngrxModule: 'store',
    },
    schema: [],
    messages: {
      [noTypedStore]:
        '`Store` should not be typed, use `Store` (without generic) instead.',
      [noTypedStoreSuggest]: 'Remove generic from `Store`.',
    },
  },
  defaultOptions: [],
  create: (context) => {
    return {
      Program() {
        const { identifiers = [] } = getNgRxStores(context);

        for (const identifier of identifiers) {
          // using inject()
          if (!identifier.typeAnnotation) {
            const { parent } = identifier;
            if (
              isPropertyDefinition(parent) &&
              parent.value &&
              isCallExpression(parent.value) &&
              parent.value.arguments.length
            ) {
              const [storeArgument] = parent.value.arguments;
              if (isTSInstantiationExpression(storeArgument)) {
                report(storeArgument.typeArguments);
              }
            }

            continue;
          }

          if (
            !isTSTypeReference(identifier.typeAnnotation.typeAnnotation) ||
            !identifier.typeAnnotation.typeAnnotation.typeArguments
          ) {
            continue;
          }

          report(identifier.typeAnnotation.typeAnnotation.typeArguments);
        }
      },
    };

    function report(typeArguments: TSESTree.TSTypeParameterInstantiation) {
      context.report({
        node: typeArguments,
        messageId: noTypedStore,
        suggest: [
          {
            messageId: noTypedStoreSuggest,
            fix: (fixer) => fixer.remove(typeArguments),
          },
        ],
      });
    }
  },
});

import { ActionReducer, Action } from '../models';
import {
  isPlainObject,
  isUndefined,
  isNull,
  isNumber,
  isBoolean,
  isString,
  isArray,
  RUNTIME_CHECK_URL,
  isComponent,
} from './utils';

export function serializationCheckMetaReducer(
  reducer: ActionReducer<any, any>,
  checks: { action: (action: Action) => boolean; state: () => boolean }
): ActionReducer<any, any> {
  return function (state, action) {
    if (checks.action(action)) {
      const unserializableAction = getUnserializable(action);
      throwIfUnserializable(unserializableAction, 'action');
    }

    const nextState = reducer(state, action);

    if (checks.state()) {
      const unserializableState = getUnserializable(nextState);
      throwIfUnserializable(unserializableState, 'state');
    }

    return nextState;
  };
}

function getUnserializable(
  target?: any,
  path: string[] = []
): false | { path: string[]; value: any } {
  // Guard against undefined and null, e.g. a reducer that returns undefined
  if ((isUndefined(target) || isNull(target)) && path.length === 0) {
    return {
      path: ['root'],
      value: target,
    };
  }

  const keys = Object.keys(target);
  return keys.reduce<false | { path: string[]; value: any }>((result, key) => {
    if (result) {
      return result;
    }

    const value = (target as any)[key];

    // Ignore Ivy components
    if (isComponent(value)) {
      return result;
    }

    if (
      isUndefined(value) ||
      isNull(value) ||
      isNumber(value) ||
      isBoolean(value) ||
      isString(value) ||
      isArray(value)
    ) {
      return false;
    }

    if (isPlainObject(value)) {
      return getUnserializable(value, [...path, key]);
    }

    return {
      path: [...path, key],
      value,
    };
  }, false);
}

function throwIfUnserializable(
  unserializable: false | { path: string[]; value: any },
  context: 'state' | 'action'
) {
  if (unserializable === false) {
    return;
  }

  const unserializablePath = unserializable.path.join('.');
  const error: any = new Error(
    `Detected unserializable ${context} at "${unserializablePath}". ${RUNTIME_CHECK_URL}#strict${context}serializability`
  );
  error.value = unserializable.value;
  error.unserializablePath = unserializablePath;
  throw error;
}

